Hi @yume-chan 👋

In my last project — [Adb-Device-Manager-2](https://github.com/Shrey113/Adb-Device-Manager-2)
— I’ve been experimenting with a similar idea for dual audio playback in Desktop Mode.

Here’s what I did:

I first start capturing one app’s audio via

scrcpy --audio-match-package-names=com.netease.cloudmusic

which streams that app’s audio to Windows.

Then, I send an HTTP request to my custom Android service that handles multi-audio routing.

That service uses AudioManager and MediaSessionManager logic (see below) to re-enable playback on another app, effectively allowing two apps to play audio simultaneously — one routed through scrcpy (Windows), and another staying on the Android device.

Here’s the core code I used:
----------------------------------------------------------

package com.example.notification_event

import android.content.ComponentName
import android.content.Context
import android.media.*
import android.media.session.MediaController
import android.media.session.MediaSessionManager
import android.media.session.PlaybackState
import android.os.Build
import android.util.Log
import fi.iki.elonen.NanoHTTPD
import kotlinx.coroutines.*
import org.json.JSONObject

class AudioRouter(private val context: Context) {

    companion object {
        private const val TAG = "AudioRouter"
    }

    private val scope = CoroutineScope(Dispatchers.IO)
    private var ignoreFocus = true

    // 🧠 Entry point
    fun handleRequest(session: NanoHTTPD.IHTTPSession): NanoHTTPD.Response {
        val action = session.parameters["action"]?.firstOrNull()?.lowercase()
        val json = JSONObject()

        if (action.isNullOrEmpty()) {
            json.put("status", "error").put("message", "Missing action")
            return jsonResponse(NanoHTTPD.Response.Status.BAD_REQUEST, json)
        }

        try {
            val msm = context.getSystemService(Context.MEDIA_SESSION_SERVICE) as MediaSessionManager
            val cn = ComponentName(context, MediaPlaybackListenerService::class.java)
            val sessions = msm.getActiveSessions(cn).filter { it.playbackState != null }

            if (sessions.isEmpty()) {
                json.put("status", "error").put("message", "No active sessions")
                return jsonResponse(NanoHTTPD.Response.Status.NOT_FOUND, json)
            }

            when (action) {
                "start" -> {
                    Log.d(TAG, "🎧 Start request")

                    // Step 0️⃣ — OEM specific pre-bypass setup
                    setupOEMBypass()

                    // Step 1️⃣ — Pause all first (forces state reset)
                    sessions.forEach { safePause(it) }

                    // Step 2️⃣ — Focus bypass (global unlock)
                    bypassAudioFocus()

                    // Step 3️⃣ — Resume playback async
                    sessions.forEach { ctrl ->
                        scope.launch { startWithRetry(ctrl) }
                    }

                    json.put("status", "success")
                        .put("message", "Relaxed multi-app playback triggered")
                }

                "stop" -> {
                    sessions.forEach { safePause(it) }
                    json.put("status", "success").put("message", "Playback stopped")
                }

                else -> {
                    json.put("status", "error").put("message", "Unknown action: $action")
                }
            }

            return jsonResponse(NanoHTTPD.Response.Status.OK, json)
        } catch (e: Exception) {
            Log.e(TAG, "❌ Error: ${e.message}", e)
            json.put("status", "error").put("message", e.message ?: "Unexpected error")
            return jsonResponse(NanoHTTPD.Response.Status.INTERNAL_ERROR, json)
        }
    }

    // 🪶 OEM detection + best trick per vendor
    private fun setupOEMBypass() {
        val manufacturer = Build.MANUFACTURER.lowercase()
        Log.d(TAG, "🔍 Device manufacturer: $manufacturer")

        when {
            manufacturer.contains("samsung") -> {
                Log.d(TAG, "🎛 Samsung detected — using relaxed focus + silent tone combo")
                ignoreAudioFocusForever()
                fakeAudioPresence()
            }
            manufacturer.contains("xiaomi") || manufacturer.contains("redmi") -> {
                Log.d(TAG, "🔊 Xiaomi detected — using persistent focus bypass")
                ignoreAudioFocusForever()
            }
            manufacturer.contains("oneplus") -> {
                Log.d(TAG, "🎧 OnePlus detected — using dual trick combo")
                ignoreAudioFocusForever()
                fakeAudioPresence()
            }
            else -> {
                Log.d(TAG, "🧩 Default Android — standard focus bypass only")
                bypassAudioFocus()
            }
        }
    }

    // 🎯 Primary bypass method (request + abandon)
    private fun bypassAudioFocus() {
        try {
            val am = context.getSystemService(Context.AUDIO_SERVICE) as AudioManager
            val attr = AudioAttributes.Builder()
                .setUsage(AudioAttributes.USAGE_MEDIA)
                .setContentType(AudioAttributes.CONTENT_TYPE_MUSIC)
                .build()

            val listener = AudioManager.OnAudioFocusChangeListener { change ->
                if (ignoreFocus) Log.d(TAG, "🪶 Ignoring focus change: $change")
            }

            val req = AudioFocusRequest.Builder(AudioManager.AUDIOFOCUS_GAIN_TRANSIENT_MAY_DUCK)
                .setAudioAttributes(attr)
                .setOnAudioFocusChangeListener(listener)
                .setWillPauseWhenDucked(false)
                .build()

            val res = am.requestAudioFocus(req)
            Log.d(TAG, "🎧 Transient focus requested ($res), now abandoning")
            am.abandonAudioFocusRequest(req)
            Log.d(TAG, "🪶 Focus abandoned — playback unlocked")
        } catch (e: Exception) {
            Log.e(TAG, "⚠ bypassAudioFocus failed: ${e.message}")
        }
    }

    // 🚫 Permanent focus override (never abandon)
    private fun ignoreAudioFocusForever() {
        try {
            val am = context.getSystemService(Context.AUDIO_SERVICE) as AudioManager
            val attr = AudioAttributes.Builder()
                .setUsage(AudioAttributes.USAGE_MEDIA)
                .setContentType(AudioAttributes.CONTENT_TYPE_MUSIC)
                .build()

            val listener = AudioManager.OnAudioFocusChangeListener { /* do nothing */ }

            val req = AudioFocusRequest.Builder(AudioManager.AUDIOFOCUS_GAIN)
                .setAudioAttributes(attr)
                .setOnAudioFocusChangeListener(listener)
                .setWillPauseWhenDucked(false)
                .setAcceptsDelayedFocusGain(false)
                .build()

            val res = am.requestAudioFocus(req)
            Log.d(TAG, "🧠 Persistent fake focus locked (res=$res)")
        } catch (e: Exception) {
            Log.e(TAG, "⚠ ignoreAudioFocusForever failed: ${e.message}")
        }
    }

    // 🔇 Keeps system "ducked" with silent tone
    private fun fakeAudioPresence() {
        try {
            val am = context.getSystemService(Context.AUDIO_SERVICE) as AudioManager
            val attr = AudioAttributes.Builder()
                .setUsage(AudioAttributes.USAGE_ASSISTANCE_SONIFICATION)
                .setContentType(AudioAttributes.CONTENT_TYPE_SONIFICATION)
                .build()

            val listener = AudioManager.OnAudioFocusChangeListener { /* ignore */ }

            val req = AudioFocusRequest.Builder(AudioManager.AUDIOFOCUS_GAIN_TRANSIENT_MAY_DUCK)
                .setAudioAttributes(attr)
                .setOnAudioFocusChangeListener(listener)
                .setWillPauseWhenDucked(false)
                .build()

            am.requestAudioFocus(req)
            am.abandonAudioFocusRequest(req)

            // Small silent tone to maintain duck state
            val tone = ToneGenerator(AudioManager.STREAM_MUSIC, 1)
            tone.startTone(ToneGenerator.TONE_SUP_DIAL, 400)
            tone.release()

            Log.d(TAG, "🔇 Silent tone trigger sent (focus duck mode active)")
        } catch (e: Exception) {
            Log.e(TAG, "⚠ fakeAudioPresence failed: ${e.message}")
        }
    }

    // ▶ Retry-based media playback starter
    private suspend fun startWithRetry(ctrl: MediaController) {
        val pkg = ctrl.packageName
        val controls = ctrl.transportControls

        repeat(3) { attempt ->
            try {
                controls.play()
                delay(350)

                val state = ctrl.playbackState?.state
                if (state == PlaybackState.STATE_PLAYING) {
                    Log.d(TAG, "✅ $pkg playing (attempt ${attempt + 1})")
                    return
                } else {
                    Log.w(TAG, "⚠ $pkg not yet playing, retrying...")
                }
            } catch (e: Exception) {
                Log.e(TAG, "❌ Failed to control $pkg: ${e.message}")
            }
        }
        Log.e(TAG, "❌ $pkg failed after retries")
    }

    private fun safePause(ctrl: MediaController) {
        try {
            ctrl.transportControls.pause()
            Log.d(TAG, "⏹ Paused ${ctrl.packageName}")
        } catch (e: Exception) {
            Log.e(TAG, "⚠ Could not pause ${ctrl.packageName}: ${e.message}")
        }
    }

    private fun jsonResponse(status: NanoHTTPD.Response.Status, json: JSONObject): NanoHTTPD.Response {
        return NanoHTTPD.newFixedLengthResponse(status, "application/json", json.toString())
    }
}
